{"code": "import json
import re

# Get stored data
languages_data = locals()['var_functions.query_db:14']
readme_data = locals()['var_functions.query_db:12']

# Extract repo names that do NOT use Python
non_python_repos = []
for lang in languages_data:
    repo_name = lang['repo_name']
    lang_desc = lang['language_description'].lower()
    # Check if Python is mentioned
    if 'python' not in lang_desc:
        non_python_repos.append(repo_name)

# Check which non-Python repos have READMEs
df_readmes = {readme['sample_repo_name']: readme for readme in readme_data}
non_python_readmes = {repo: df_readmes[repo] for repo in non_python_repos if repo in df_readmes}

print('__RESULT__:')
print(json.dumps({
    'non_python_repos': len(non_python_repos),
    'non_python_readmes': len(non_python_readmes)
}))"}

